SELECT
    '采购入库' as type, DATE_FORMAT(inbound_date, '%Y-%m-%d') as date, COUNT(*) as count, SUM(inbound_qty) as total_qty
FROM purchase_inbound
WHERE status = '1'
AND inbound_date >= #{startDate}
AND inbound_date <= #{endDate}
GROUP BY DATE_FORMAT(inbound_date, '%Y-%m-%d')
UNION ALL
SELECT '采购退货' as type, DATE_FORMAT(return_date, '%Y-%m-%d') as date, COUNT(*) as count, SUM(return_qty) as total_qty
FROM purchase_return WHERE status = '1'
AND return_date >= #{startDate}
AND return_date <= #{endDate}
GROUP BY DATE_FORMAT(return_date, '%Y-%m-%d')
UNION ALL
SELECT '销售出库' as type, DATE_FORMAT(outbound_date, '%Y-%m-%d') as date, COUNT(*) as count, SUM(outbound_qty) as total_qty
FROM sales_outbound WHERE status = '1'
AND outbound_date >= #{startDate}
AND outbound_date <= #{endDate}
GROUP BY DATE_FORMAT(outbound_date, '%Y-%m-%d')
UNION ALL
SELECT '销售退货入库' as type, DATE_FORMAT(return_date, '%Y-%m-%d') as date, COUNT(*) as count, SUM(return_qty) as total_qty
FROM sales_return WHERE status = '1'
AND return_date >= #{startDate}
AND return_date <= #{endDate}
GROUP BY DATE_FORMAT(return_date, '%Y-%m-%d')
ORDER BY date

SELECT c.check_id, c.material_name, c.book_qty, c.actual_qty, c.diff_qty, c.diff_reason, c.check_date, c.approval_status
FROM inventory_check c

    AND c.check_date >= #{startDate}
    AND c.check_date <= #{endDate}

ORDER BY c.check_date DESC
